using System;
using System.Data;
using System.Data.SqlClient;

public static bool ValidateLoginCredentials(string username, string password)
{
    using (var conn = new SqlConnection("Server=myServerAddress;Database=myDataBase;User Id=myUsername;Password=myPassword"))
    {
        conn.Open();
        var cmd = new SqlCommand("SELECT COUNT(*) FROM myTable WHERE username = @username AND password = @password", conn);
        cmd.Parameters.AddWithValue("@username", username);
        cmd.Parameters.AddWithValue("@password", password);
        var count = Convert.ToInt32(cmd.ExecuteScalar());
